diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index f9155cc66031..9ab526591515 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -30,6 +30,7 @@
 #include "llvm/Support/Casting.h"
 #include "llvm/Support/KnownBits.h"
 #include "llvm/Transforms/InstCombine/InstCombiner.h"
+#include "llvm/Support/raw_ostream.h"
 #include <cassert>
 #include <utility>

@@ -2221,7 +2222,8 @@ Value *InstCombinerImpl::OptimizePointerDifference(Value *LHS, Value *RHS,
 }

 static Instruction *foldSubOfMinMax(BinaryOperator &I,
-                                    InstCombiner::BuilderTy &Builder) {
+                                     InstCombiner::BuilderTy &Builder) {
+
   Value *Op0 = I.getOperand(0);
   Value *Op1 = I.getOperand(1);
   Type *Ty = I.getType();
@@ -2254,6 +2256,8 @@ static Instruction *foldSubOfMinMax(BinaryOperator &I,
     }
   }

+  // sub Op0, smin((sub nsw Op0, Z), 0) --> smax Op0, Z
+  // sub Op0, smax((sub nsw Op0, Z), 0) --> smin Op0, Z
   // sub Op0, smin((sub nsw Op0, Z), 0) --> smax Op0, Z
   // sub Op0, smax((sub nsw Op0, Z), 0) --> smin Op0, Z
   if (MinMax->isSigned() && match(Y, m_ZeroInt()) &&
@@ -2262,6 +2266,69 @@ static Instruction *foldSubOfMinMax(BinaryOperator &I,
     Function *F = Intrinsic::getOrInsertDeclaration(I.getModule(), InvID, Ty);
     return CallInst::Create(F, {Op0, Z});
   }
+  // sub(smin(A + C, B), smin(A, B)) --> (A < B) ? C : 0, where C = 1/-1 and no-wrap.
+  auto *MinMax2 = dyn_cast<MinMaxIntrinsic>(Op0);
+  if (MinMax2 && MinMax2->getIntrinsicID() == MinMax->getIntrinsicID()) {
+    // Match both intrinsics with a common operand and the other operand differs by a constant.
+    Value *Common = nullptr;
+    Value *DiffOp1 = nullptr;
+    Value *DiffOp2 = nullptr;
+    // Check all possible pairings for a common operand.
+    if (MinMax->getLHS() == MinMax2->getLHS()) {
+      Common = MinMax->getLHS();
+      DiffOp1 = MinMax->getRHS();
+      DiffOp2 = MinMax2->getRHS();
+    } else if (MinMax->getLHS() == MinMax2->getRHS()) {
+      Common = MinMax->getLHS();
+      DiffOp1 = MinMax->getRHS();
+      DiffOp2 = MinMax2->getLHS();
+    } else if (MinMax->getRHS() == MinMax2->getLHS()) {
+      Common = MinMax->getRHS();
+      DiffOp1 = MinMax->getLHS();
+      DiffOp2 = MinMax2->getRHS();
+    } else if (MinMax->getRHS() == MinMax2->getRHS()) {
+      Common = MinMax->getRHS();
+      DiffOp1 = MinMax->getLHS();
+      DiffOp2 = MinMax2->getLHS();
+    }
+    if (!Common) return nullptr;
+    const APInt *C;
+    bool AddIsInOp0 = false; // whether the add is in Op0 (MinMax2)
+    // Check if DiffOp2 = DiffOp1 + C, with appropriate no-wrap.
+    if (match(DiffOp2, m_Add(m_Specific(DiffOp1), m_APInt(C)))) {
+      AddIsInOp0 = true; // DiffOp2 belongs to MinMax2 (Op0)
+    } else if (match(DiffOp1, m_Add(m_Specific(DiffOp2), m_APInt(C)))) {
+      AddIsInOp0 = false; // DiffOp1 belongs to MinMax (Op1)
+      std::swap(DiffOp1, DiffOp2);
+    } else {
+      return nullptr;
+    }
+    // Only handle C = 1 or -1.
+    // Only handle C = 1 or -1.
+    if (!(C->isOne() || C->isAllOnes())) return nullptr;
+    auto *Add = dyn_cast<BinaryOperator>(AddIsInOp0 ? DiffOp2 : DiffOp1);
+    if (!Add) return nullptr;
+    bool IsSigned = MinMax->isSigned();
+    if (IsSigned ? Add->hasNoSignedWrap() : Add->hasNoUnsignedWrap()) {
+      ICmpInst::Predicate Pred;
+      if (MinMax->getIntrinsicID() == Intrinsic::smin ||
+          MinMax->getIntrinsicID() == Intrinsic::umin) {
+        // min: diff = (DiffOp1 < Common) ? C : 0
+        Pred = IsSigned ? ICmpInst::ICMP_SLT : ICmpInst::ICMP_ULT;
+      } else {
+        // max: diff = (DiffOp1 > Common) ? C : 0
+        Pred = IsSigned ? ICmpInst::ICMP_SGT : ICmpInst::ICMP_UGT;
+      }
+      // Determine sign factor: if add is in Op0, diff = C; else diff = -C.
+      APInt SignedC = *C;
+      if (!AddIsInOp0) SignedC = -SignedC;
+      Value *Cmp = Builder.CreateICmp(Pred, DiffOp1, Common);
+      Constant *ConstC = ConstantInt::get(Ty, SignedC);
+      Constant *Zero = ConstantInt::get(Ty, 0);
+      return SelectInst::Create(Cmp, ConstC, Zero);
+      return SelectInst::Create(Cmp, ConstC, Zero);
+    }
+  }

   return nullptr;
 }

